import { readFileSync, existsSync } from "fs";
import { resolve } from "path";

/**
 * Parses a .env file content into a key-value object.
 * Handles:
 *  - Comments (#)
 *  - Quoted values (single and double)
 *  - Inline comments
 *  - Multiline values (double-quoted with \n)
 *  - Export prefix
 *
 * @param {string} content - Raw .env file content
 * @returns {Record<string, string>}
 */
export function parse(content) {
  const result = {};
  const lines = content.split(/\r?\n/);

  let i = 0;
  while (i < lines.length) {
    let line = lines[i].trim();
    i++;

    // Skip empty lines and comments
    if (!line || line.startsWith("#")) continue;

    // Strip optional "export " prefix
    if (line.startsWith("export ")) {
      line = line.slice(7).trim();
    }

    const eqIndex = line.indexOf("=");
    if (eqIndex === -1) continue;

    const key = line.slice(0, eqIndex).trim();
    if (!key || !/^[A-Za-z_][A-Za-z0-9_]*$/.test(key)) continue;

    let raw = line.slice(eqIndex + 1).trim();
    let value;

    // Double-quoted: support escape sequences and multiline
    if (raw.startsWith('"')) {
      let inner = raw.slice(1);
      // Collect continuation lines until closing quote
      while (!inner.includes('"') && i < lines.length) {
        inner += "\n" + lines[i];
        i++;
      }
      const closeIdx = inner.indexOf('"');
      if (closeIdx !== -1) {
        inner = inner.slice(0, closeIdx);
      }
      value = inner
        .replace(/\\n/g, "\n")
        .replace(/\\r/g, "\r")
        .replace(/\\t/g, "\t")
        .replace(/\\\\/g, "\\")
        .replace(/\\"/g, '"');
    }
    // Single-quoted: literal, no escape processing
    else if (raw.startsWith("'")) {
      const closeIdx = raw.indexOf("'", 1);
      value = closeIdx !== -1 ? raw.slice(1, closeIdx) : raw.slice(1);
    }
    // Unquoted: strip inline comments
    else {
      const commentIdx = raw.search(/\s+#/);
      value = (commentIdx !== -1 ? raw.slice(0, commentIdx) : raw).trim();
    }

    result[key] = value;
  }

  return result;
}

/**
 * Loads a .env file from disk and parses it.
 *
 * @param {string} [path] - Path to .env file (defaults to process.cwd()/.env)
 * @returns {Record<string, string>}
 */
export function loadFile(path) {
  const filePath = path || resolve(process.cwd(), ".env");

  if (!existsSync(filePath)) {
    return {};
  }

  const content = readFileSync(filePath, "utf8");
  return parse(content);
}
